<?php namespace App\Repositories\Academic;use App\Repositories\BaseRepository;use App\Models\Academic\Section;use Illuminate\Database\Eloquent\Collection;class SectionRepository extends BaseRepository{    public function __construct(Section $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Section    {        return $this->query()->where('name', $name)->first();    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function getActiveSections(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function searchSections(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getSectionWithStudents(int $sectionId): ?Section    {        return $this->query()->with('students')->findOrFail($sectionId);    }    public function countStudentsBySection(int $classId): Collection    {        return $this->query()->where('class_id', $classId)->withCount('students')->get();    }    public function getByTeacher(int $employeeId): Collection    {        return $this->query()->whereHas('timetables', function ($q) use ($employeeId) {                $q->whereHas('periods', function ($q2) use ($employeeId) {                    $q2->where('employee_id', $employeeId);                });            })->get();    }}